const sharp = require\('sharp'\);
const fs = require\('fs'\);
const path = require\('path'\);

const srcDir = 'C:/Users/cjhoo/Desktop/Images/jeffConnersArtworks';
const outDir = 'C:/Users/cjhoo/Desktop/Images/jeffConnersArtworks/previews';

fs.mkdirSync\(outDir, { recursive: true }\);

const files = fs.readdirSync\(srcDir\).filter\(f => /\\.\(heic|png|jpg|jpeg\)$/i.test\(f\)\);

async function convert\(\) {
  for \(const f of files\) {
    try {
      await sharp\(path.join\(srcDir, f\)\)
        .rotate\(\)
        .resize\(800, 800, { fit: 'inside', withoutEnlargement: true }\)
        .jpeg\({ quality: 70 }\)
        .toFile\(path.join\(outDir, f.replace\(/\\.\\w+$/, '.jpg'\)\)\);
      console.log\('OK:', f\);
    } catch \(e\) {
      console.log\('FAIL:', f, e.message\);
    }
  }
}
convert\(\);
